import {
  BrowserRouter,
  Routes,
  Route,
  Link
} from "react-router-dom";

import Login from "./pages/Login";
import Signup from "./pages/Signup";
import Dashboard from "./pages/Dashboard";

function App() {
  return (
    <BrowserRouter>

      <div
        style={{
          padding: "20px",
          display: "flex",
          gap: "20px"
        }}
      >
        <Link to="/">
          Login
        </Link>

        <Link to="/signup">
          Signup
        </Link>

        <Link to="/dashboard">
          Dashboard
        </Link>

      </div>

      <Routes>

        <Route
          path="/"
          element={<Login />}
        />

        <Route
          path="/signup"
          element={<Signup />}
        />

        <Route
          path="/dashboard"
          element={<Dashboard />}
        />

      </Routes>

    </BrowserRouter>
  );
}

export default App;
